/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const N = nums.length;
    if (N < 3) {
        return 0;
    }

    const N_prime = N - 2; // Number of potential peak indices: 1 to N-2
    const K_max = Math.ceil(N_prime / 2);

    // 1. Calculate costs C_i for i = 1 to N-2
    // C[i] stores the cost for index i. We use 1-based indexing for convenience here.
    const C = new Array(N); // Index 0 unused, Index 1 to N-2 used.
    const INF = Number.MAX_SAFE_INTEGER;

    for (let i = 1; i <= N_prime; i++) {
        // Cost to make index i a peak, assuming neighbors remain unchanged.
        const left_val = nums[i - 1];
        const right_val = nums[i + 1];
        const required_val = Math.max(left_val, right_val) + 1;
        const cost = Math.max(0, required_val - nums[i]);
        C[i] = cost;
    }

    // 2. Dynamic Programming
    // DP[r][j]: Minimum cost to select exactly j non-adjacent peaks from the set {1, 2, ..., r}.
    // r runs from 0 to N_prime (r=0 is empty prefix, r=N_prime is the whole range).
    // j runs from 0 to K_max.

    // We need N_prime + 1 rows (0 to N_prime) and K_max + 1 columns (0 to K_max).
    const DP = Array(N_prime + 1).fill(0).map(() => Array(K_max + 1).fill(INF));

    // Base case: 0 peaks from empty set costs 0.
    DP[0][0] = 0;

    for (let r = 1; r <= N_prime; r++) { // r corresponds to the current index i=r
        const cost_r = C[r];
        for (let j = 0; j <= K_max; j++) {

            // Case 1: Skip index r (Do not select r)
            // We inherit the best result from the prefix ending at r-1.
            DP[r][j] = DP[r - 1][j];

            // Case 2: Select index r (Pick r)
            if (j > 0) {
                let previous_cost = INF;

                if (r === 1) {
                    // If r=1, the previous state must be DP[0][j-1]. This is only possible if j=1, where DP[0][0]=0.
                    if (j === 1) {
                        previous_cost = 0;
                    }
                } else {
                    // If r > 1, the previous selection must end at r-2.
                    previous_cost = DP[r - 2][j - 1];
                }

                if (previous_cost !== INF) {
                    const current_cost = previous_cost + cost_r;
                    DP[r][j] = Math.min(DP[r][j], current_cost);
                }
            }
        }
    }

    // The result is the minimum cost to select K_max peaks from the entire range [1, N_prime].
    return DP[N_prime][K_max];
}

