fun solve(nums: Array<Long>): Long {
    val N = nums.size
    if (N < 3) {
        return 0L
    }

    // Potential peak indices are i = 1 to N - 2. N_prime is the count of such indices.
    val N_prime = N - 2
    // Maximum number of non-adjacent peaks possible.
    val K_max = (N_prime + 1) / 2

    // 1. Calculate costs C[i] for i = 1 to N - 2.
    // We use a 1-indexed array for costs, size N+1.
    val C = LongArray(N + 1) { 0L }

    for (i in 1 until N - 1) {
        val leftVal = nums[i - 1]
        val rightVal = nums[i + 1]

        // Required value must be > max(neighbors)
        val requiredVal = maxOf(leftVal, rightVal) + 1L

        // Cost is max(0, requiredVal - nums[i])
        val cost = maxOf(0L, requiredVal - nums[i])
        C[i] = cost
    }

    // 2. Dynamic Programming: Minimum cost to select exactly j non-adjacent peaks from {1, ..., r}.
    // We use rolling arrays for O(K_max) space complexity.
    // INF must be large enough but prevent overflow when adding C[i] (~10^14 max cost).
    val INF = Long.MAX_VALUE / 2

    // DP_A corresponds to DP[r-2]
    // DP_B corresponds to DP[r-1]
    // DP_C corresponds to DP[r] (current step)

    // Initialize DP_A (r=-1, effectively empty prefix before index 1)
    var dpA = LongArray(K_max + 1) { INF }
    dpA[0] = 0L

    // Initialize DP_B (r=0, effectively empty prefix)
    var dpB = LongArray(K_max + 1) { INF }
    dpB[0] = 0L

    var dpC = LongArray(K_max + 1) { 0L } // Will be initialized properly inside the loop

    // Iterate r from 1 up to N_prime (i.e., array index 1 to N-2)
    for (r in 1..N_prime) {
        val cr = C[r]

        // Reset dpC for the current iteration r
        dpC.fill(INF)
        dpC[0] = 0L // Always 0 cost for 0 peaks

        for (j in 1..K_max) {

            // Case 1: Skip index r (Inherit from r-1)
            val skipCost = dpB[j]
            dpC[j] = skipCost

            // Case 2: Select index r (Must come from r-2)
            if (dpA[j - 1] != INF) {
                val pickCost = dpA[j - 1] + cr
                dpC[j] = minOf(dpC[j], pickCost)
            }
        }

        // Shift states for the next iteration: DP_A <- DP_B, DP_B <- DP_C
        dpA = dpB.copyOf()
        dpB = dpC.copyOf()
        dpC = LongArray(K_max + 1) { 0L } // Prepare new DP_C for the next loop
    }

    // The result is the minimum cost to select K_max peaks from the entire range [1, N_prime].
    return dpB[K_max]
}

